    settings: DEFAULT_AI_SETTINGS,
    loaded: false,
    saving: false,
    toast: null,
    showAddProvider: false,
    newProviderType: "openai",
    newProviderName: "",
    newProviderKey: "",
    newProviderBaseUrl: "",
    testingProviderId: null,
    testResults: {},
    discoveringProviderId: null,
    providerModelErrors: {},
    editingProviderId: null,
    editKey: "",
    openFeature: null,
    defaultCitationStyle: "mla",
