  const refreshProviderModels = $(async (id: string) => {
    const provider = store.settings.providers.find((p) => p.id === id);
    if (!provider) return;
    store.discoveringProviderId = id;
    store.providerModelErrors = {
      ...store.providerModelErrors,
      [id]: undefined,
