            style="font-family: var(--font-typewriter);"
          >
            Continue to the editor →
          </button>
        </div>
      </div>
    );
  }

  if (store.style === "conversational") {
    return (
      <ConversationalInterview
        mode="first-run"
        onComplete$={completeOnboarding$}
        onCancel$={$(() => {
          store.style = "form";
        })}
        cancelLabel="Use form"
      />
    );
  }

  return (
    <AntiTabulaRasa
      mode="first-run"
      initialAnswers={null}
      onSubmit$={completeOnboarding$}
      onCancel$={onCancel$}
    />
  );
});

