/* ── Public: build full settings from partial ───────────────────── */

export function normalizeAiSettings(
  partial: Partial<AiSettings> | null,
): AiSettings {
  const defaults: AiSettings = {
    advancedMode: false,
    providers: [],
    defaultProviderId: null,
    perFeature: {},
    showProviderTags: false,
  };
  const base: AiSettings = !partial
    ? defaults
    : {
        ...defaults,
        ...partial,
        providers: partial.providers ?? [],
        perFeature: partial.perFeature ?? {},
      };
  return withDesktopLocalProvider(stripManagedDesktopLocalProvider(base));
}

/** Remove the transient desktop-local provider before persisting settings. */
export function stripManagedDesktopLocalProvider(
  settings: AiSettings,
): AiSettings {
  const providers = settings.providers.filter(
    (p) => p.id !== LOCAL_PROVIDER_ID,
  );
  const defaultProviderId =
    settings.defaultProviderId === LOCAL_PROVIDER_ID
      ? (providers[0]?.id ?? null)
      : settings.defaultProviderId;
  const perFeature = Object.fromEntries(
    Object.entries(settings.perFeature).filter(
      ([, override]) => override?.providerId !== LOCAL_PROVIDER_ID,
    ),
  ) as AiSettings["perFeature"];

  return {
    ...settings,
    providers,
    defaultProviderId,
    perFeature,
  };
}

/**
 * When running inside the Electrobun desktop shell with the local LiteRT model
 * available, inject a managed `litert` provider so every panel can use it
 * without the writer configuring anything. No-op on the web (the bridge
 * reports unavailable), so the local surface stays hidden there.
 */
function withDesktopLocalProvider(settings: AiSettings): AiSettings {
  const baseUrl = localAiBaseUrl();
  if (!baseUrl) return settings;

  const local: AiProviderConfig = {
    id: LOCAL_PROVIDER_ID,
    name: "Local — Gemma 4 E4B",
    type: "litert",
    apiKey: "local",
    baseUrl,
    defaultModel: LOCAL_MODEL_ID,
    availableModels: [LOCAL_MODEL_ID],
  };
  const providers = settings.providers.some((p) => p.id === LOCAL_PROVIDER_ID)
    ? settings.providers.map((p) => (p.id === LOCAL_PROVIDER_ID ? local : p))
    : [...settings.providers, local];

  return {
    ...settings,
    advancedMode: true,
    providers,
    // Only claim the default slot if the writer hasn't chosen one.
    defaultProviderId: settings.defaultProviderId ?? LOCAL_PROVIDER_ID,
  };
}

/* ── Conversational interview (BYOK) ────────────────────────────── */

import type { ProjectBrief, ProjectInterviewAnswers } from "../types";

export type InterviewConfidence = "high" | "medium" | "low";

export interface InterviewMessage {
  author: "writer" | "interviewer";
  text: string;
}
import { describe, expect, test } from "bun:test";
import type { AiFeature, AiSettings } from "../types";
import { hasConfiguredAiProvider, resolveFeatureConfig } from "./ai-client";

const ALL_FEATURES: AiFeature[] = [
  "persona-feedback",
  "persona-reply",
  "persona-rewrite",
  "rubric-judge",
  "voice-narration",
  "comment-reply",
  "citation-format",
  "source-summarize",
  "source-detect-missing",
  "interview-turn",
  "dossier-check",
];

function makeSettings(overrides: Partial<AiSettings> = {}): AiSettings {
  return {
    advancedMode: false,
    providers: [
      {
        id: "provider-openai",
        name: "OpenAI",
        type: "openai",
        apiKey: "sk-test",
        defaultModel: "gpt-5.5-mini",
        availableModels: ["gpt-5.5-mini", "gpt-5.5-nano"],
      },
    ],
    defaultProviderId: "provider-openai",
    perFeature: {},
    showProviderTags: false,
    ...overrides,
  };
}

describe("ai-client provider resolution", () => {
  test("treats configured providers as active even when advancedMode is false", () => {
    const settings = makeSettings({ advancedMode: false });

    expect(hasConfiguredAiProvider(settings)).toBe(true);

    const resolved = resolveFeatureConfig(settings, "persona-feedback");
    expect(resolved?.provider.id).toBe("provider-openai");
    expect(resolved?.model).toBe("gpt-5.5-mini");
  });

  test("resolves every AI feature against the configured provider set", () => {
    const settings = makeSettings({ advancedMode: false });

    for (const feature of ALL_FEATURES) {
      const resolved = resolveFeatureConfig(settings, feature);
      expect(resolved).not.toBeNull();
      expect(resolved?.provider.id).toBe("provider-openai");
      expect(typeof resolved?.model).toBe("string");
      expect(resolved?.model.length).toBeGreaterThan(0);
    }

    expect(resolveFeatureConfig(settings, "voice-narration")?.model).toBe(
      "gpt-4o-mini-tts",
    );
  });

  test("respects per-feature provider and model overrides", () => {
    const settings = makeSettings({
      providers: [
        {
          id: "provider-openai",
          name: "OpenAI",
          type: "openai",
          apiKey: "sk-openai",
          defaultModel: "gpt-5.5-mini",
          availableModels: ["gpt-5.5-mini"],
        },
        {
          id: "provider-anthropic",
          name: "Anthropic",
          type: "anthropic",
          apiKey: "sk-anthropic",
          defaultModel: "claude-sonnet-4-6",
          availableModels: ["claude-sonnet-4-6", "claude-haiku-4-6"],
        },
      ],
      perFeature: {
        "citation-format": {
          providerId: "provider-anthropic",
          model: "claude-haiku-4-6",
          temperature: 0.1,
          maxTokens: 180,
        },
      },
    });

    const resolved = resolveFeatureConfig(settings, "citation-format");
    expect(resolved?.provider.id).toBe("provider-anthropic");
    expect(resolved?.model).toBe("claude-haiku-4-6");
    expect(resolved?.temperature).toBe(0.1);
    expect(resolved?.maxTokens).toBe(180);
  });
});

