export async function savePersonasToIdb(personas: Persona[]): Promise<void> {
  if (!isBrowser()) return;
  try {
    await tx("personas", "readwrite", async (t) => {
      const store = t.objectStore("personas");
      store.clear();
      for (const p of personas) store.put(p);
    });
  } catch {
    /* ignore */
  }
}

