function extractTaggedJson(
  text: string,
  tag: "DOSSIER" | "SYNTHESIZE",
): { value: unknown; start: number; end: number } | null {
  const marker = new RegExp(`${tag}:`, "i").exec(text);
  if (!marker) return null;
  const open = text.indexOf("{", marker.index + marker[0].length);
  if (open < 0) return null;

  let depth = 0;
  let inString = false;
  let escaped = false;
  for (let i = open; i < text.length; i += 1) {
    const ch = text[i];
    if (escaped) {
      escaped = false;
      continue;
    }
    if (ch === "\\") {
      escaped = true;
      continue;
    }
    if (ch === '"') {
      inString = !inString;
      continue;
    }
    if (inString) continue;
    if (ch === "{") depth += 1;
    if (ch === "}") {
      depth -= 1;
      if (depth === 0) {
        try {
          return {
            value: JSON.parse(text.slice(open, i + 1)),
            start: marker.index,
            end: i + 1,
          };
        } catch {
          return null;
        }
      }
    }
  }
  return null;
}

