                typeof c.reason === "string"
                  ? c.reason.trim()
                  : "Needs verifiable source",
              suggestedQuery:
                typeof c.suggestedQuery === "string"
                  ? c.suggestedQuery.trim()
                  : String(c.claim).trim(),
            })),
          provider: resolved.provider.type,
        };
      }
    } catch {
      /* fall through */
    }
    return null;
  } catch (err) {
    console.warn("[twyne:ai-client] missing source detect failed:", err);
