export interface JudgeResult {
  personaId: string;
  score: number;
  rationale: string;
  provider: string;
}

export interface RubricCombineResult {
  judgeMean: number; // 0-10
  staticTotal: number; // 0-10
  combined: number; // 0-100
  grade: string;
  summary: string;
}

const JUDGE_WEIGHT = 0.7;
const STATIC_WEIGHT = 0.3;

