}

export function ensureFeedbackPassageReference(
  text: string,
  req: AgentRequest,
): string {
  const cleaned = text.trim();
  if (!cleaned) return cleaned;
  if (/^(?:on|passage|line)\s*:/i.test(cleaned)) return cleaned;

  const passage = selectFeedbackPassage(req);
  const prefix = passage ? `On: "${passage}"` : "On: (no draft text yet)";
  return `${prefix}\n\n${cleaned}`;
}

function selectFeedbackPassage(req: AgentRequest): string | null {
  const anchor = req.anchor?.trim();
  if (anchor) return clampPassage(anchor);

  const draft = req.draftText.trim();
  if (!draft) return null;

  const firstLine = draft
    .split(/\r?\n/)
    .map((line) => line.trim())
    .find(Boolean);
  if (!firstLine) return null;

  const sentence = firstLine.match(/^(.{24,240}?[.!?])(?:\s|$)/)?.[1];
  return clampPassage(sentence ?? firstLine);
}

function clampPassage(text: string): string {
  const singleLine = text.replace(/\s+/g, " ").trim();
  if (singleLine.length <= 240) return singleLine;
  const clipped = singleLine.slice(0, 240);
  return clipped.replace(/\s+\S*$/, "").trim() || clipped.trim();
}

