import { extractDynamicFeedbackAnchor } from "./persona-anchors";

const draft = [
  "The opening claims too much before the reader has evidence.",
  "The second paragraph finally gives the piece a spine.",
  "The closing sentence should stop before it explains itself twice.",
].join("\n\n");

describe("extractDynamicFeedbackAnchor", () => {
  test("uses the exact On quote emitted by the persona", () => {
    expect(
      extractDynamicFeedbackAnchor(
        'On: "The second paragraph finally gives the piece a spine."\n\nThis is the working hinge.',
        draft,
      ),
    ).toBe("The second paragraph finally gives the piece a spine.");
  });

  test("does not fall back to the first draft line when no quote is present", () => {
    expect(
      extractDynamicFeedbackAnchor("This note has no quoted passage.", draft),
    ).toBeUndefined();
  });

  test("ignores quotes that are not present in the draft", () => {
    expect(
      extractDynamicFeedbackAnchor(
        'On: "A sentence the model invented."\n\nThis should not pin.',
        draft,
      ),
    ).toBeUndefined();
  });
});

